import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getVehicles } from "../../api/vehicleApi";

function VehicleList() {
  const [vehicles, setVehicles] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    getVehicles()
      .then((res) => setVehicles(res.data))
      .catch((err) => console.error(err));
  }, []);

  const bookNow = (vehicleId, status) => {
    if (status !== "available") {
      alert("This vehicle is not available for booking.");
      return;
    }

    const token = localStorage.getItem("token");
    if (!token) {
      alert("Please login to book an appointment.");
      navigate("/login");
      return;
    }

    navigate("/book-appointment", {
      state: { vehicleId },
    });
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Vehicles</h2>

      {vehicles.map((v) => (
        <div
          key={v._id}
          style={{
            border: "1px solid #ccc",
            margin: "8px 0",
            padding: "12px",
            borderRadius: 8,
          }}
        >
          <p>
            <strong>
              {v.brand} {v.model || v.type || ""}
            </strong>
          </p>
          <p>Year: {v.year}</p>
          <p>Price: Rs. {Number(v.price).toLocaleString()}</p>
          <p>Status: {v.status}</p>

          <button
            onClick={() => bookNow(v._id, v.status)}
            disabled={v.status !== "available"}
            style={{
              padding: "8px 12px",
              cursor: v.status === "available" ? "pointer" : "not-allowed",
              opacity: v.status === "available" ? 1 : 0.6,
            }}
          >
            Book Appointment
          </button>
        </div>
      ))}
    </div>
  );
}

export default VehicleList;
